import { useEffect } from 'react';

export default function SEO({ title, description, keywords, image, url, type = 'website' }) {
  useEffect(() => {
    // Update document title
    document.title = title ? `${title} | Aura Alpha` : 'Aura Alpha — Autonomous Trading Platform';

    // Helper to set/create meta tag
    const setMeta = (property, content) => {
      if (!content) return;
      let el = document.querySelector(`meta[property="${property}"]`) ||
               document.querySelector(`meta[name="${property}"]`);
      if (!el) {
        el = document.createElement('meta');
        el.setAttribute(property.startsWith('og:') || property.startsWith('twitter:') ? 'property' : 'name', property);
        document.head.appendChild(el);
      }
      el.setAttribute('content', content);
    };

    // Standard meta
    setMeta('description', description);
    if (keywords) setMeta('keywords', keywords);

    // Open Graph
    setMeta('og:title', title || 'Aura Alpha');
    setMeta('og:description', description);
    setMeta('og:image', image || 'https://auraalpha.cc/aura-og.png');
    setMeta('og:url', url || window.location.href);
    setMeta('og:type', type);
    setMeta('og:site_name', 'Aura Alpha');

    // Twitter Card
    setMeta('twitter:card', 'summary_large_image');
    setMeta('twitter:title', title || 'Aura Alpha');
    setMeta('twitter:description', description);
    setMeta('twitter:image', image || 'https://auraalpha.cc/aura-og.png');

    // Update canonical link
    const canonicalUrl = url || `https://auraalpha.cc${window.location.pathname}`;
    let canonical = document.querySelector('link[rel="canonical"]');
    if (canonical) canonical.setAttribute('href', canonicalUrl);

    return () => {
      // Reset on unmount
      document.title = 'Aura Alpha — Autonomous Trading Platform';
    };
  }, [title, description, keywords, image, url, type]);

  return null; // This component renders nothing
}
